const { test, expect } = require('@playwright/test');

test('Verify header links', async ({ page }) => {
  await page.setViewportSize({ width: 375, height: 812 });
  await page.goto('http://localhost:3002/');

  const links = await page.$$eval('header a, nav a', (els) => els.map(el => ({ text: el.innerText.trim(), href: el.getAttribute('href') })));

  // Verify Home link
  const home = links.find(l => l.text.toLowerCase() === 'home');
  expect(home, 'Home link should be present').toBeDefined();

  // Verify Contact link
  const contact = links.find(l => l.text.toLowerCase() === 'contact');
  expect(contact?.href).toBe('/contact');

  // Verify other links
  expect(links.find(l => l.text.toLowerCase() === 'blog')?.href).toBe('/blog');
  expect(links.find(l => l.text.toLowerCase() === 'portfolio')?.href).toBe('/portfolio');
  expect(links.find(l => l.text.toLowerCase() === 'videos')?.href).toBe('/videos');
});
